import React from 'react';
import styled from 'styled-components';
import { device } from '../utils/breakpoints';

const HeroSection = styled.section`
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  background: linear-gradient(135deg, #0f2027 0%, #203a43 50%, #2c5364 100%);
  color: #ffffff;
  padding: 2rem;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background:
      radial-gradient(circle at 20% 50%, rgba(120, 119, 198, 0.1) 0%, transparent 50%),
      radial-gradient(circle at 80% 80%, rgba(33, 150, 243, 0.1) 0%, transparent 50%);
    pointer-events: none;
  }
`;

const ContentWrapper = styled.div`
  max-width: 900px;
  text-align: center;
  position: relative;
  z-index: 1;
`;

const Eyebrow = styled.p`
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 3px;
  color: #64B5F6;
  margin-bottom: 1rem;
  font-weight: 500;
  opacity: 0.9;

  @media ${device.tablet} {
    font-size: 1rem;
  }
`;

const MainHeading = styled.h1`
  font-size: 2.5rem;
  font-weight: 700;
  color: #ffffff;
  margin-bottom: 1.5rem;
  line-height: 1.2;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

  @media ${device.tablet} {
    font-size: 3.5rem;
  }

  @media ${device.laptop} {
    font-size: 4rem;
  }

  span {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
`;

const Subtitle = styled.p`
  font-size: 1.1rem;
  color: #B0BEC5;
  margin-bottom: 2.5rem;
  line-height: 1.6;
  max-width: 700px;
  margin-left: auto;
  margin-right: auto;

  @media ${device.tablet} {
    font-size: 1.3rem;
  }
`;

const CTAContainer = styled.div`
  display: flex;
  gap: 1rem;
  flex-direction: column;
  align-items: center;

  @media ${device.tablet} {
    flex-direction: row;
    justify-content: center;
  }
`;

const PrimaryButton = styled.a`
  display: inline-block;
  padding: 1rem 2.5rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: #ffffff;
  text-decoration: none;
  font-weight: 600;
  border-radius: 8px;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.3);
  font-size: 1rem;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
  }

  &:active {
    transform: translateY(0);
  }
`;

const SecondaryButton = styled.a`
  display: inline-block;
  padding: 1rem 2.5rem;
  background: transparent;
  color: #ffffff;
  text-decoration: none;
  font-weight: 600;
  border-radius: 8px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  transition: all 0.3s ease;
  font-size: 1rem;

  &:hover {
    border-color: rgba(255, 255, 255, 0.6);
    background: rgba(255, 255, 255, 0.05);
  }
`;

const SpecialtiesSection = styled.section`
  padding: 4rem 2rem;
  background: #ffffff;
`;

const SpecialtiesWrapper = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  font-size: 2rem;
  font-weight: 700;
  color: #1a1a1a;
  text-align: center;
  margin-bottom: 3rem;

  @media ${device.tablet} {
    font-size: 2.5rem;
  }
`;

const SpecialtiesGrid = styled.div`
  display: grid;
  grid-template-columns: 1fr;
  gap: 2rem;

  @media ${device.tablet} {
    grid-template-columns: repeat(3, 1fr);
  }
`;

const SpecialtyCard = styled.div`
  padding: 2rem;
  background: #f8f9fa;
  border-radius: 12px;
  border: 1px solid #e0e0e0;
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
    border-color: #667eea;
  }
`;

const SpecialtyIcon = styled.div`
  font-size: 2.5rem;
  margin-bottom: 1rem;
`;

const SpecialtyTitle = styled.h3`
  font-size: 1.3rem;
  font-weight: 600;
  color: #1a1a1a;
  margin-bottom: 0.75rem;
`;

const SpecialtyDescription = styled.p`
  font-size: 0.95rem;
  color: #546e7a;
  line-height: 1.6;
`;

const HomePage = () => (
  <>
    <HeroSection>
      <ContentWrapper>
        <Eyebrow>AI Consultant & Solutions Architect</Eyebrow>
        <MainHeading>
          Joël Tiogo
        </MainHeading>
        <Subtitle>
          Bridging AI technology and business strategy to drive measurable outcomes in automotive analytics, sustainability, and enterprise solutions.
        </Subtitle>
        <CTAContainer>
          <PrimaryButton href="/about">View Experience</PrimaryButton>
          <SecondaryButton href="mailto:tiogojoel@gmail.com">Get in Touch</SecondaryButton>
        </CTAContainer>
      </ContentWrapper>
    </HeroSection>

    <SpecialtiesSection>
      <SpecialtiesWrapper>
        <SectionTitle>Core Expertise</SectionTitle>
        <SpecialtiesGrid>
          <SpecialtyCard>
            <SpecialtyIcon>🤖</SpecialtyIcon>
            <SpecialtyTitle>AI/ML Solutions</SpecialtyTitle>
            <SpecialtyDescription>
              Architecting production-ready machine learning systems with expertise in TensorFlow, PyTorch, and cloud AI platforms.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>📊</SpecialtyIcon>
            <SpecialtyTitle>Business Strategy</SpecialtyTitle>
            <SpecialtyDescription>
              Translating complex AI capabilities into ROI-driven strategies for C-level stakeholders across international markets.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🌍</SpecialtyIcon>
            <SpecialtyTitle>Global Markets</SpecialtyTitle>
            <SpecialtyDescription>
              Trilingual professional (French, English, German) with proven track record in European, African, and North American markets.
            </SpecialtyDescription>
          </SpecialtyCard>
        </SpecialtiesGrid>
      </SpecialtiesWrapper>
    </SpecialtiesSection>
  </>
);

export default HomePage;
